object SecurityConfig {
    // Allowed origins that can be loaded in the WebView
    val ALLOWED_ORIGINS = setOf(
        "https://app.example.com",
        "https://cdn.example.com",
        "https://api.example.com"
    )

    // The primary app URL
    const val APP_URL = "https://app.example.com"

    // Allowed bridge actions (whitelist of native functions callable from web)
    val ALLOWED_ACTIONS = setOf(
        "openCamera",
        "capturePhoto",
        "getLocalStorage",
        "setLocalStorage",
        "removeLocalStorage",
        "clearLocalStorage",
        "requestPushPermission",
        "getPushToken",
        "isPushEnabled",
        "getDeviceInfo",
        "hapticFeedback"
    )

    // Maximum message payload size in bytes
    const val MAX_PAYLOAD_SIZE = 1024 * 64 // 64KB

    // Rate limiting: max calls per second per action
    const val MAX_CALLS_PER_SECOND = 10

    fun isOriginAllowed(url: String?): Boolean {
        if (url == null) return false
        return ALLOWED_ORIGINS.any { origin ->
            url.startsWith(origin)
        }
    }

    fun isActionAllowed(action: String?): Boolean {
        return action != null && action in ALLOWED_ACTIONS
    }
}


