package com.example.hybridapp.bridge

import com.google.gson.Gson
import com.google.gson.JsonSyntaxException
import com.google.gson.annotations.SerializedName

data class BridgeMessage(
    @SerializedName("id") val id: String,
    @SerializedName("action") val action: String,
    @SerializedName("payload") val payload: Map<String, Any?>? = null
) {
    companion object {
        private val gson = Gson()

        fun fromJson(json: String): BridgeMessage? {
            return try {
                val message = gson.fromJson(json, BridgeMessage::class.java)
                if (message.id.isBlank() || message.action.isBlank()) null
                else message
            } catch (e: JsonSyntaxException) {
                null
            } catch (e: Exception) {
                null
            }
        }
    }
}

data class BridgeResponse(
    @SerializedName("id") val id: String,
    @SerializedName("action") val action: String,
    @SerializedName("success") val success: Boolean,
    @SerializedName("data") val data: Any? = null,
    @SerializedName("error") val error: String? = null
) {
    fun toJson(): String {
        return Gson().toJson(this)
    }
}


