package com.example.hybridapp.bridge

import java.util.concurrent.ConcurrentHashMap
import java.util.concurrent.atomic.AtomicInteger
import java.util.concurrent.atomic.AtomicLong

class RateLimiter(private val maxCallsPerSecond: Int) {
    private val actionCounters = ConcurrentHashMap<String, ActionCounter>()

    data class ActionCounter(
        val count: AtomicInteger = AtomicInteger(0),
        val windowStart: AtomicLong = AtomicLong(System.currentTimeMillis())
    )

    fun isAllowed(action: String): Boolean {
        val now = System.currentTimeMillis()
        val counter = actionCounters.getOrPut(action) { ActionCounter() }

        synchronized(counter) {
            if (now - counter.windowStart.get() > 1000) {
                counter.count.set(0)
                counter.windowStart.set(now)
            }
            return counter.count.incrementAndGet() <= maxCallsPerSecond
        }
    }

    fun reset() {
        actionCounters.clear()
    }
}


