package com.example.hybridapp.bridge

import com.example.hybridapp.config.SecurityConfig

class MessageValidator {

    sealed class ValidationResult {
        data class Valid(val message: BridgeMessage) : ValidationResult()
        data class Invalid(val reason: String) : ValidationResult()
    }

    fun validate(rawJson: String): ValidationResult {
        // Check payload size
        if (rawJson.toByteArray(Charsets.UTF_8).size > SecurityConfig.MAX_PAYLOAD_SIZE) {
            return ValidationResult.Invalid("Payload exceeds maximum size limit")
        }

        // Parse message
        val message = BridgeMessage.fromJson(rawJson)
            ?: return ValidationResult.Invalid("Invalid message format")

        // Validate message ID (prevent injection)
        if (!message.id.matches(Regex("^[a-zA-Z0-9_-]{1,64}$"))) {
            return ValidationResult.Invalid("Invalid message ID format")
        }

        // Validate action is whitelisted
        if (!SecurityConfig.isActionAllowed(message.action)) {
            return ValidationResult.Invalid("Action '${message.action}' is not allowed")
        }

        // Validate payload values (no script injection in string values)
        if (message.payload != null && !validatePayloadValues(message.payload)) {
            return ValidationResult.Invalid("Payload contains invalid values")
        }

        return ValidationResult.Valid(message)
    }

    private fun validatePayloadValues(payload: Map<String, Any?>): Boolean {
        for ((key, value) in payload) {
            // Validate key
            if (!key.matches(Regex("^[a-zA-Z0-9_.\\-]{1,128}$"))) {
                return false
            }
            // Validate string values don't contain script tags or dangerous content
            if (value is String) {
                if (value.length > 1024 * 32) return false // 32KB max per string value
                val lower = value.lowercase()
                if (lower.contains("<script") || lower.contains("javascript:")) {
                    return false
                }
            }
            // Recursively validate nested maps
            @Suppress("UNCHECKED_CAST")
            if (value is Map<*, *>) {
                if (!validatePayloadValues(value as Map<String, Any?>)) return false
            }
        }
        return true
    }
}


