package com.example.hybridapp.bridge

import android.util.Log
import android.webkit.JavascriptInterface

/**
 * Minimal JavaScript interface exposed to WebView.
 * Only a single entry point is exposed to minimize attack surface.
 */
class NativeBridgeInterface(
    private val onMessage: (String) -> Unit
) {
    companion object {
        const val INTERFACE_NAME = "NativeBridge"
        private const val TAG = "NativeBridgeInterface"
    }

    @JavascriptInterface
    fun postMessage(messageJson: String) {
        Log.d(TAG, "Received message from web")
        onMessage(messageJson)
    }
}


