package com.example.hybridapp.bridge

import android.content.Context
import android.content.SharedPreferences
import android.os.Build
import android.os.VibrationEffect
import android.os.Vibrator
import android.os.VibratorManager
import android.util.Log
import android.webkit.WebView
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.example.hybridapp.config.SecurityConfig
import kotlinx.coroutines.*

class BridgeHandler(
    private val context: Context,
    private val webView: WebView,
    private val onCameraRequest: (String) -> Unit,
    private val onPushPermissionRequest: (String) -> Unit
) {
    companion object {
        private const val TAG = "BridgeHandler"
        private const val PREFS_NAME = "hybrid_app_storage"
    }

    private val validator = MessageValidator()
    private val rateLimiter = RateLimiter(SecurityConfig.MAX_CALLS_PER_SECOND)
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())
    private val securePrefs: SharedPreferences by lazy { createSecurePrefs() }

    private fun createSecurePrefs(): SharedPreferences {
        return try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()
            EncryptedSharedPreferences.create(
                context,
                PREFS_NAME,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (e: Exception) {
            Log.w(TAG, "Failed to create encrypted prefs, falling back to standard", e)
            context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        }
    }

    fun handleMessage(rawJson: String) {
        when (val result = validator.validate(rawJson)) {
            is MessageValidator.ValidationResult.Valid -> {
                val message = result.message
                if (!rateLimiter.isAllowed(message.action)) {
                    sendError(message.id, message.action, "Rate limit exceeded")
                    return
                }
                processMessage(message)
            }
            is MessageValidator.ValidationResult.Invalid -> {
                Log.w(TAG, "Invalid message rejected: ${result.reason}")
                // Don't send detailed error info back to potentially malicious caller
            }
        }
    }

    private fun processMessage(message: BridgeMessage) {
        scope.launch {
            try {
                when (message.action) {
                    // Camera actions
                    "openCamera" -> handleOpenCamera(message)
                    "capturePhoto" -> handleCapturePhoto(message)

                    // Local storage actions
                    "getLocalStorage" -> handleGetLocalStorage(message)
                    "setLocalStorage" -> handleSetLocalStorage(message)
                    "removeLocalStorage" -> handleRemoveLocalStorage(message)
                    "clearLocalStorage" -> handleClearLocalStorage(message)

                    // Push notification actions
                    "requestPushPermission" -> handleRequestPushPermission(message)
                    "getPushToken" -> handleGetPushToken(message)
                    "isPushEnabled" -> handleIsPushEnabled(message)

                    // Device actions
                    "getDeviceInfo" -> handleGetDeviceInfo(message)
                    "hapticFeedback" -> handleHapticFeedback(message)

                    else -> sendError(message.id, message.action, "Unknown action")
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error processing message: ${message.action}", e)
                sendError(message.id, message.action, "Internal error")
            }
        }
    }

    // --- Camera Handlers ---

    private fun handleOpenCamera(message: BridgeMessage) {
        onCameraRequest(message.id)
    }

    private fun handleCapturePhoto(message: BridgeMessage) {
        onCameraRequest(message.id)
    }

    fun onCameraResult(messageId: String, success: Boolean, imageUri: String?) {
        if (success && imageUri != null) {
            sendSuccess(messageId, "capturePhoto", mapOf("uri" to imageUri))
        } else {
            sendError(messageId, "capturePhoto", "Camera capture failed or was cancelled")
        }
    }

    // --- Local Storage Handlers ---

    private fun handleGetLocalStorage(message: BridgeMessage) {
        val key = message.payload?.get("key") as? String
        if (key.isNullOrBlank()) {
            sendError(message.id, message.action, "Key is required")
            return
        }
        val sanitizedKey = sanitizeStorageKey(key)
        if (sanitizedKey == null) {
            sendError(message.id, message.action, "Invalid key format")
            return
        }
        val value = securePrefs.getString(sanitizedKey, null)
        sendSuccess(message.id, message.action, mapOf("key" to sanitizedKey, "value" to value))
    }

    private fun handleSetLocalStorage(message: BridgeMessage) {
        val key = message.payload?.get("key") as? String
        val value = message.payload?.get("value") as? String
        if (key.isNullOrBlank()) {
            sendError(message.id, message.action, "Key is required")
            return
        }
        val sanitizedKey = sanitizeStorageKey(key)
        if (sanitizedKey == null) {
            sendError(message.id, message.action, "Invalid key format")
            return
        }
        if (value != null && value.length > 1024 * 16) {
            sendError(message.id, message.action, "Value too large")
            return
        }
        securePrefs.edit().putString(sanitizedKey, value ?: "").apply()
        sendSuccess(message.id, message.action, mapOf("key" to sanitizedKey))
    }

    private fun handleRemoveLocalStorage(message: BridgeMessage) {
        val key = message.payload?.get("key") as? String
        if (key.isNullOrBlank()) {
            sendError(message.id, message.action, "Key is required")
            return
        }
        val sanitizedKey = sanitizeStorageKey(key)
        if (sanitizedKey == null) {
            sendError(message.id, message.action, "Invalid key format")
            return
        }
        securePrefs.edit().remove(sanitizedKey).apply()
        sendSuccess(message.id, message.action, mapOf("key" to sanitizedKey))
    }

    private fun handleClearLocalStorage(message: BridgeMessage) {
        securePrefs.edit().clear().apply()
        sendSuccess(message.id, message.action, null)
    }

    private fun sanitizeStorageKey(key: String): String? {
        if (key.length > 256) return null
        if (!key.matches(Regex("^[a-zA-Z0-9_.\\-:/]{1,256}$"))) return null
        return key
    }

    // --- Push Notification Handlers ---

    private fun handleRequestPushPermission(message: BridgeMessage) {
        onPushPermissionRequest(message.id)
    }

    fun onPushPermissionResult(messageId: String, granted: Boolean) {
        sendSuccess(messageId, "requestPushPermission", mapOf("granted" to granted))
    }

    private fun handleGetPushToken(message: BridgeMessage) {
        // In a real app, retrieve from Firebase or other push service
        val token = securePrefs.getString("push_token", null)
        sendSuccess(message.id, message.action, mapOf("token" to token))
    }

    fun updatePushToken(token: String) {
        securePrefs.edit().putString("push_token", token).apply()
    }

    private fun handleIsPushEnabled(message: BridgeMessage) {
        val enabled = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            context.checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) ==
                    android.content.pm.PackageManager.PERMISSION_GRANTED
        } else {
            true
        }
        sendSuccess(message.id, message.action, mapOf("enabled" to enabled))
    }

    // --- Device Info Handler ---

    private fun handleGetDeviceInfo(message: BridgeMessage) {
        val info = mapOf(
            "platform" to "android",
            "osVersion" to Build.VERSION.RELEASE,
            "sdkVersion" to Build.VERSION.SDK_INT,
            "manufacturer" to Build.MANUFACTURER,
            "model" to Build.MODEL,
            "appVersion" to getAppVersion()
        )
        sendSuccess(message.id, message.action, info)
    }

    private fun getAppVersion(): String {
        return try {
            val pInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            pInfo.versionName ?: "unknown"
        } catch (e: Exception) {
            "unknown"
        }
    }

    // --- Haptic Feedback Handler ---

    private fun handleHapticFeedback(message: BridgeMessage) {
        val type = message.payload?.get("type") as? String ?: "light"
        try {
            val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val vibratorManager = context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as VibratorManager
                vibratorManager.defaultVibrator
            } else {
                @Suppress("DEPRECATION")
                context.getSystemService(Context.VIBRATOR_SERVICE) as Vibrator
            }

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                val effect = when (type) {
                    "light" -> VibrationEffect.createOneShot(10, VibrationEffect.DEFAULT_AMPLITUDE)
                    "medium" -> VibrationEffect.createOneShot(30, VibrationEffect.DEFAULT_AMPLITUDE)
                    "heavy" -> VibrationEffect.createOneShot(50, VibrationEffect.DEFAULT_AMPLITUDE)
                    else -> VibrationEffect.createOneShot(10, VibrationEffect.DEFAULT_AMPLITUDE)
                }
                vibrator.vibrate(effect)
            } else {
                @Suppress("DEPRECATION")
                vibrator.vibrate(10)
            }
            sendSuccess(message.id, message.action, null)
        } catch (e: Exception) {
            sendError(message.id, message.action, "Haptic feedback not available")
        }
    }

    // --- Response Helpers ---

    private fun sendSuccess(id: String, action: String, data: Any?) {
        val response = BridgeResponse(id = id, action = action, success = true, data = data)
        sendToWeb(response)
    }

    private fun sendError(id: String, action: String, error: String) {
        val response = BridgeResponse(id = id, action = action, success = false, error = error)
        sendToWeb(response)
    }

    private fun sendToWeb(response: BridgeResponse) {
        val json = response.toJson().replace("\\", "\\\\").replace("'", "\\'")
        scope.launch(Dispatchers.Main) {
            webView.evaluateJavascript(
                "javascript:window.dispatchEvent(new CustomEvent('nativeBridgeResponse', {detail: JSON.parse('$json')}));",
                null
            )
        }
    }

    fun destroy() {
        scope.cancel()
        rateLimiter.reset()
    }
}


