package com.example.hybridapp.webview

import android.graphics.Bitmap
import android.net.http.SslError
import android.util.Log
import android.webkit.SslErrorHandler
import android.webkit.WebResourceError
import android.webkit.WebResourceRequest
import android.webkit.WebView
import android.webkit.WebViewClient
import com.example.hybridapp.config.SecurityConfig

class SecureWebViewClient(
    private val onPageStarted: ((String?) -> Unit)? = null,
    private val onPageFinished: ((String?) -> Unit)? = null,
    private val onError: ((String?) -> Unit)? = null
) : WebViewClient() {

    companion object {
        private const val TAG = "SecureWebViewClient"
    }

    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
        val url = request?.url?.toString() ?: return true

        // Only allow navigation to whitelisted origins
        if (!SecurityConfig.isOriginAllowed(url)) {
            Log.w(TAG, "Blocked navigation to non-allowed origin: $url")
            return true // Block navigation
        }

        return false // Allow navigation
    }

    override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
        super.onPageStarted(view, url, favicon)

        // Verify the URL is still allowed
        if (url != null && !SecurityConfig.isOriginAllowed(url)) {
            Log.w(TAG, "Page started loading from non-allowed origin: $url")
            view?.stopLoading()
            return
        }

        onPageStarted?.invoke(url)
    }

    override fun onPageFinished(view: WebView?, url: String?) {
        super.onPageFinished(view, url)

        // Inject the bridge initialization script
        view?.evaluateJavascript(getBridgeInitScript(), null)

        onPageFinished?.invoke(url)
    }

    override fun onReceivedSslError(view: WebView?, handler: SslErrorHandler?, error: SslError?) {
        Log.e(TAG, "SSL Error: ${error?.primaryError}")
        // NEVER call handler.proceed() in production - always cancel
        handler?.cancel()
        onError?.invoke("SSL Error: ${error?.primaryError}")
    }

    override fun onReceivedError(
        view: WebView?,
        request: WebResourceRequest?,
        error: WebResourceError?
    ) {
        super.onReceivedError(view, request, error)
        if (request?.isForMainFrame == true) {
            Log.e(TAG, "Page load error: ${error?.description}")
            onError?.invoke(error?.description?.toString())
        }
    }

    /**
     * JavaScript bridge initialization code injected into every page.
     * Provides a clean API for web content to call native functions.
     */
    private fun getBridgeInitScript(): String {
        return """
            (function() {
                if (window.__nativeBridgeInitialized) return;
                window.__nativeBridgeInitialized = true;
                
                const pendingCallbacks = new Map();
                
                window.addEventListener('nativeBridgeResponse', function(event) {
                    const response = event.detail;
                    if (response && response.id && pendingCallbacks.has(response.id)) {
                        const { resolve, reject, timeout } = pendingCallbacks.get(response.id);
                        clearTimeout(timeout);
                        pendingCallbacks.delete(response.id);
                        if (response.success) {
                            resolve(response.data);
                        } else {
                            reject(new Error(response.error || 'Unknown error'));
                        }
                    }
                });
                
                function generateId() {
                    return 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
                }
                
                function callNative(action, payload, timeoutMs) {
                    timeoutMs = timeoutMs || 30000;
                    return new Promise(function(resolve, reject) {
                        var id = generateId();
                        var timeout = setTimeout(function() {
                            pendingCallbacks.delete(id);
                            reject(new Error('Native call timed out'));
                        }, timeoutMs);
                        
                        pendingCallbacks.set(id, { resolve: resolve, reject: reject, timeout: timeout });
                        
                        var message = JSON.stringify({
                            id: id,
                            action: action,
                            payload: payload || {}
                        });
                        
                        if (window.NativeBridge && window.NativeBridge.postMessage) {
                            window.NativeBridge.postMessage(message);
                        } else {
                            pendingCallbacks.delete(id);
                            clearTimeout(timeout);
                            reject(new Error('Native bridge not available'));
                        }
                    });
                }
                
                // Public API
                window.HybridApp = {
                    camera: {
                        open: function() { return callNative('openCamera'); },
                        capture: function() { return callNative('capturePhoto'); }
                    },
                    storage: {
                        get: function(key) { return callNative('getLocalStorage', { key: key }); },
                        set: function(key, value) { return callNative('setLocalStorage', { key: key, value: value }); },
                        remove: function(key) { return callNative('removeLocalStorage', { key: key }); },
                        clear: function() { return callNative('clearLocalStorage'); }
                    },
                    push: {
                        requestPermission: function() { return callNative('requestPushPermission'); },
                        getToken: function() { return callNative('getPushToken'); },
                        isEnabled: function() { return callNative('isPushEnabled'); }
                    },
                    device: {
                        getInfo: function() { return callNative('getDeviceInfo'); },
                        haptic: function(type) { return callNative('hapticFeedback', { type: type || 'light' }); }
                    },
                    isAvailable: function() { return !!(window.NativeBridge && window.NativeBridge.postMessage); }
                };
                
                // Dispatch ready event
                window.dispatchEvent(new CustomEvent('hybridAppReady'));
                console.log('[HybridApp] Native bridge initialized');
            })();
        """.trimIndent()
    }
}


