package com.example.hybridapp.webview

import android.net.Uri
import android.webkit.ConsoleMessage
import android.webkit.PermissionRequest
import android.webkit.ValueCallback
import android.webkit.WebChromeClient
import android.webkit.WebView
import android.util.Log

class SecureWebChromeClient(
    private val onFileChooser: ((ValueCallback<Array<Uri>>?) -> Boolean)? = null,
    private val onPermissionRequest: ((PermissionRequest?) -> Unit)? = null
) : WebChromeClient() {

    companion object {
        private const val TAG = "SecureWebChromeClient"
        // Only allow camera permission from WebView
        private val ALLOWED_PERMISSIONS = setOf(
            PermissionRequest.RESOURCE_VIDEO_CAPTURE
        )
    }

    override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
        Log.d(TAG, "WebView Console: ${consoleMessage?.message()} " +
                "(${consoleMessage?.sourceId()}:${consoleMessage?.lineNumber()})")
        return true
    }

    override fun onShowFileChooser(
        webView: WebView?,
        filePathCallback: ValueCallback<Array<Uri>>?,
        fileChooserParams: FileChooserParams?
    ): Boolean {
        return onFileChooser?.invoke(filePathCallback) ?: false
    }

    override fun onPermissionRequest(request: PermissionRequest?) {
        request?.let { req ->
            val allowedResources = req.resources.filter { it in ALLOWED_PERMISSIONS }.toTypedArray()
            if (allowedResources.isNotEmpty()) {
                onPermissionRequest?.invoke(req)
            } else {
                Log.w(TAG, "Denied WebView permission request: ${req.resources.joinToString()}")
                req.deny()
            }
        }
    }
}


