        private const val TAG = "MainActivity"
    }

    private lateinit var webView: WebView
    private lateinit var progressBar: ProgressBar
    private lateinit var errorView: TextView
    private lateinit var bridgeHandler: BridgeHandler

    // Camera handling
    private var pendingCameraMessageId: String? = null
    private var cameraImageUri: Uri? = null
    private var filePathCallback: ValueCallback<Array<Uri>>? = null

    // Push notification handling
    private var pendingPushMessageId: String? = null

    // Permission launchers
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var cameraActivityLauncher: ActivityResultLauncher<Intent>
    private lateinit var pushPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setupLayout()
        registerActivityResultLaunchers()
        setupWebView()
        loadApp()
    }

    private fun setupLayout() {
        val rootLayout = FrameLayout(this).apply {
            layoutParams = FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT,
                FrameLayout.LayoutParams.MATCH_PARENT
            )
        }

        webView = WebView(this).apply {
            layoutParams = FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT,
                FrameLayout.LayoutParams.MATCH_PARENT
            )
        }

        progressBar = ProgressBar(this).apply {
            layoutParams = FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.WRAP_CONTENT,
                FrameLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                gravity = android.view.Gravity.CENTER
            }
            visibility = View.VISIBLE
        }

        errorView = TextView(this).apply {
            layoutParams = FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.WRAP_CONTENT,
                FrameLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                gravity = android.view.Gravity.CENTER
            }
            visibility = View.GONE
            textSize = 16f
            setPadding(32, 32, 32, 32)
        }

        rootLayout.addView(webView)
        rootLayout.addView(progressBar)
        rootLayout.addView(errorView)

        setContentView(rootLayout)
    }

    private fun registerActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { granted ->
            if (granted) {
                launchCamera()
            } else {
                pendingCameraMessageId?.let { id ->
                    bridgeHandler.onCameraResult(id, false, null)
                    pendingCameraMessageId = null
                }
            }
        }

        cameraActivityLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            val messageId = pendingCameraMessageId
            pendingCameraMessageId = null

            if (result.resultCode == RESULT_OK && cameraImageUri != null) {
                messageId?.let { id ->
                    bridgeHandler.onCameraResult(id, true, cameraImageUri.toString())
                }
                // Also handle file chooser callback if active
                filePathCallback?.onReceiveValue(arrayOf(cameraImageUri!!))
                filePathCallback = null
            } else {
                messageId?.let { id ->
                    bridgeHandler.onCameraResult(id, false, null)
                }
                filePathCallback?.onReceiveValue(null)
                filePathCallback = null
            }
        }

        pushPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { granted ->
            pendingPushMessageId?.let { id ->
                bridgeHandler.onPushPermissionResult(id, granted)
                pendingPushMessageId = null
            }
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == RESULT_OK) {
                val data = result.data?.data
                filePathCallback?.onReceiveValue(if (data != null) arrayOf(data) else null)
            } else {
                filePathCallback?.onReceiveValue(null)
            }
            filePathCallback = null
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        // Initialize bridge handler
        bridgeHandler = BridgeHandler(
            context = this,
            webView = webView,
            onCameraRequest = { messageId -> requestCamera(messageId) },
            onPushPermissionRequest = { messageId -> requestPushPermission(messageId) }
        )

        // Configure WebView settings
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = false

            // Security settings
            allowFileAccess = false
            allowContentAccess = false
            allowFileAccessFromFileURLs = false
            allowUniversalAccessFromFileURLs = false

            // Performance settings
            cacheMode = WebSettings.LOAD_DEFAULT
            mediaPlaybackRequiresUserGesture = true

            // Mixed content - block mixed content
            mixedContentMode = WebSettings.MIXED_CONTENT_NEVER_ALLOW

            // User agent
            userAgentString = "$userAgentString HybridApp/1.0"

            // Disable geolocation
            setGeolocationEnabled(false)
        }

        // Enable secure cookies
        CookieManager.getInstance().apply {
            setAcceptCookie(true)
            setAcceptThirdPartyCookies(webView, false)
        }

        // Disable WebView debugging in production
        WebView.setWebContentsDebuggingEnabled(BuildConfig.DEBUG)

        // Add JavaScript interface (single entry point)
        val bridgeInterface = NativeBridgeInterface { messageJson ->
            runOnUiThread {
                bridgeHandler.handleMessage(messageJson)
            }
        }
        webView.addJavascriptInterface(bridgeInterface, NativeBridgeInterface.INTERFACE_NAME)

        // Set WebView clients
        webView.webViewClient = SecureWebViewClient(
            onPageStarted = { _ ->
                progressBar.visibility = View.VISIBLE
                errorView.visibility = View.GONE
            },
            onPageFinished = { _ ->
                progressBar.visibility = View.GONE
            },
            onError = { errorMessage ->
                progressBar.visibility = View.GONE
                showError(errorMessage ?: "Failed to load page")
            }
        )

        webView.webChromeClient = SecureWebChromeClient(
            onFileChooser = { callback ->
                filePathCallback?.onReceiveValue(null)
                filePathCallback = callback
                openFileChooser()
                true
            },
            onPermissionRequest = { request ->
                handleWebViewPermissionRequest(request)
            }
        )
    }

    private fun loadApp() {
        webView.loadUrl(SecurityConfig.APP_URL)
    }

    // --- Camera ---

    private fun requestCamera(messageId: String) {
        pendingCameraMessageId = messageId
        when {
            ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
                    PackageManager.PERMISSION_GRANTED -> {
                launchCamera()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun launchCamera() {
        val imageFile = createImageFile() ?: run {
            pendingCameraMessageId?.let { id ->
                bridgeHandler.onCameraResult(id, false, null)
                pendingCameraMessageId = null
            }
            return
        }

        cameraImageUri = FileProvider.getUriForFile(
            this,
            "${packageName}.fileprovider",
            imageFile
        )

        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
            addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
        }

        if (intent.resolveActivity(packageManager) != null) {
            cameraActivityLauncher.launch(intent)
        } else {
            pendingCameraMessageId?.let { id ->
                bridgeHandler.onCameraResult(id, false, null)
                pendingCameraMessageId = null
            }
        }
    }

    private fun createImageFile(): File? {
        return try {
            val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
            val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
            File.createTempFile("IMG_${timeStamp}_", ".jpg", storageDir)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to create image file", e)
            null
        }
    }

    // --- File Chooser ---

    private fun openFileChooser() {
        val intent = Intent(Intent.ACTION_GET_CONTENT).apply {
            addCategory(Intent.CATEGORY_OPENABLE)
            type = "image/*"
        }
        fileChooserLauncher.launch(Intent.createChooser(intent, "Select File"))
    }

    // --- Push Notifications ---

    private fun requestPushPermission(messageId: String) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            pendingPushMessageId = messageId
            when {
                ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) ==
                        PackageManager.PERMISSION_GRANTED -> {
                    bridgeHandler.onPushPermissionResult(messageId, true)
                    pendingPushMessageId = null
                }
                else -> {
                    pushPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        } else {
            // Pre-Android 13, notifications are enabled by default
            bridgeHandler.onPushPermissionResult(messageId, true)
        }
    }

    // --- WebView Permission Requests ---

    private fun handleWebViewPermissionRequest(request: PermissionRequest?) {
        request?.let { req ->
            // Only grant camera permission if we have it
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
                PackageManager.PERMISSION_GRANTED
            ) {
                req.grant(req.resources)
            } else {
                req.deny()
            }
        }
    }

    // --- Error Display ---

    private fun showError(message: String) {
        errorView.text = "Error: $message\n\nTap to retry"
        errorView.visibility = View.VISIBLE
        errorView.setOnClickListener {
            errorView.visibility = View.GONE
            loadApp()
        }
    }

    // --- Lifecycle ---

    override fun onResume() {
        super.onResume()
        webView.onResume()
    }

    override fun onPause() {
        webView.onPause()
        super.onPause()
    }

    @Deprecated("Deprecated in Java")
    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            @Suppress("DEPRECATION")
            super.onBackPressed()
        }
    }

    override fun onDestroy() {
        bridgeHandler.destroy()
        webView.apply {
            stopLoading()
            removeJavascriptInterface(NativeBridgeInterface.INTERFACE_NAME)
            destroy()
        }
        super.onDestroy()
    }
}


